31	        public UITransitContext GetNextUpdate()
32	        {
33	            if (InputManager.UI.OpenInventory.GetKeyDown) return new UITransitContext(UIStateEnum.PlayerInventory);
34	            if (InputManager.UI.OpenMenu.GetKeyDown) return new UITransitContext(UIStateEnum.PauseMenu);
35	
36	            // 列車に乗り込む範囲＋E押下を 1 行で判定し、TrainHUDScreen へ遷移する。
37	            // One-line check for "in ride range + interact key pressed", transits to TrainHUDScreen.
38	            if (_rideVehicleInputService.TryGetInteractTransit(out var rideContext)) return rideContext;
39	
40	            // ブロックや列車とインタラクトしたか
41	            if (_subInventoryInteractService.TryGetSubInventoryInteractObject(out var context)) return context;
42	
43	            if (InputManager.UI.BlockDelete.GetKeyDown) return new UITransitContext(UIStateEnum.DeleteBar);
44	            if (_skitManager.IsPlayingSkit) return new UITransitContext(UIStateEnum.Story);
45	            
46	            //TODO InputSystemのリファクタ対象
47	            if (HybridInput.GetKeyDown(KeyCode.B)) return new UITransitContext(UIStateEnum.BuildMenu);
